{"version":3,"names":["urlIdPattern","currentColorBrush","type","contextFillBrush","contextStrokeBrush","extractBrush","color","brush","match","brushRef","processedColor","processColor","payload","console","warn","String"],"sources":["extractBrush.ts"],"sourcesContent":["import { ColorValue, processColor } from 'react-native';\n\nconst urlIdPattern = /^url\\(#(.+)\\)$/;\n\nconst currentColorBrush = { type: 2 };\nconst contextFillBrush = { type: 3 };\nconst contextStrokeBrush = { type: 4 };\n\nexport default function extractBrush(color?: ColorValue) {\n  if (!color || color === 'none') {\n    return null;\n  }\n\n  if (color === 'currentColor') {\n    return currentColorBrush;\n  }\n\n  if (color === 'context-fill') {\n    return contextFillBrush;\n  }\n\n  if (color === 'context-stroke') {\n    return contextStrokeBrush;\n  }\n\n  const brush = typeof color === 'string' && color.match(urlIdPattern);\n  if (brush) {\n    return { type: 1, brushRef: brush[1] };\n  }\n\n  const processedColor = processColor(color);\n  if (typeof processedColor === 'number') {\n    return { type: 0, payload: processedColor };\n  }\n\n  if (typeof processedColor === 'object' && processedColor !== null) {\n    // if we got an object, it should be `PlatformColor` or `DynamicColorIOS`,\n    // so we pass it as an object with `0` value as first item, which is interpreted\n    // on the native side as color to be managed by `RCTConvert`.\n    return { type: 0, payload: processedColor };\n  }\n\n  console.warn(`\"${String(color)}\" is not a valid color or brush`);\n  return null;\n}\n"],"mappings":"sFAAA,yCAEA,GAAMA,aAAY,CAAG,gBAArB,CAEA,GAAMC,kBAAiB,CAAG,CAAEC,IAAI,CAAE,CAAR,CAA1B,CACA,GAAMC,iBAAgB,CAAG,CAAED,IAAI,CAAE,CAAR,CAAzB,CACA,GAAME,mBAAkB,CAAG,CAAEF,IAAI,CAAE,CAAR,CAA3B,CAEe,QAASG,aAAT,CAAsBC,KAAtB,CAA0C,CACvD,GAAI,CAACA,KAAD,EAAUA,KAAK,GAAK,MAAxB,CAAgC,CAC9B,MAAO,KAAP,CACD,CAED,GAAIA,KAAK,GAAK,cAAd,CAA8B,CAC5B,MAAOL,kBAAP,CACD,CAED,GAAIK,KAAK,GAAK,cAAd,CAA8B,CAC5B,MAAOH,iBAAP,CACD,C